import React from 'react';
import styled from 'styled-components';

const WorkExperienceSection = () => {
  return (
      <Container>
    <AnimatedWorkExperienceSection> {/* Use the animated version of the component */}
      <Title>‍💼Work Experience</Title>
      <SectionList>
        <AnimatedSectionListItem> {/* Use the animated version of the component */}
          <SectionTitle>Advanced Application Developer Analyst Intern at Accenture, June - July, 2023</SectionTitle>
          <SectionDescription>
            <ul>
              <li>Spearheaded the development of Healthcare Chatbot and data-driven dashboards.</li>
              <li>Collaborated with cross-functional teams to deliver high-quality software solutions.</li>
            </ul>
          </SectionDescription>
        </AnimatedSectionListItem>
        <AnimatedSectionListItem> {/* Use the animated version of the component */}
          <SectionTitle>Beta Student Ambassador at Microsoft</SectionTitle>
          <SectionDescription>
            <ul>
              <li>
                Student representative for Microsoft, as part of a global community of students in technology. With exclusive access to various learning resources and events, achieved training in skills not usually taught in academia.
              </li>
            </ul>
          </SectionDescription>
        </AnimatedSectionListItem>
      </SectionList>
    </AnimatedWorkExperienceSection>
    </Container>
  );
};

export default WorkExperienceSection;

const Container = styled.div`
  max-width: 800px;
  margin: 0 auto;
  padding: 40px 20px;
`;

const Title = styled.h2`
  font-size: 32px;
  font-weight: bold;
  text-align: center;
  margin-bottom: 20px;
`;

const SectionList = styled.ul`
  list-style-type: none;
  padding: 0;
`;

const SectionListItem = styled.li`
  margin-bottom: 20px;
`;

const SectionTitle = styled.u`
  font-size: 22px;
  font-weight: bold;
`;

const SectionDescription = styled.div`
  margin-top: 10px;
  padding-left: 20px;

  ul {
    list-style-type: disc;
    padding-left: 20px;
    margin-top: 5px;
  }

  li {
    font-size: 18px;
    line-height: 1.6;
  }
`;
